// // This module implements a 3-bit synchronous counter that decrements on each clock cycle when enabled, and resets to 7 when reset.
module sync_counter(
	input clk,
	input enable,
	input reset,
	output reg [2:0] count);
always @(posedge clk) begin
	if (reset)
		count <= 0;
	else if (enable)
		count <= count + 1;
end

endmodule
